const FROM_DATE = '2026-03-01';
const TO_DATE = '2026-03-10';
// Open export modal
_ViewerElements.default.getActiveUsersExportButton.click();
_ViewerElements.default.getConcurrentUsersExportModal.should('be.visible');
// Set From Date
_ViewerElements.default.getExportFromDateInput.click({
  force: true
}).type(FROM_DATE, {
  force: true
});
// Set To Date
_ViewerElements.default.getExportToDateInput.click({
  force: true
}).type(TO_DATE, {
  force: true
});
// Verify values
_ViewerElements.default.getExportFromDateInput.should('have.value', FROM_DATE);
_ViewerElements.default.getExportToDateInput.should('have.value', TO_DATE);
// Export
_ViewerElements.default.getExportConfirmButton.click();
cy.wait(2000);
cy.exec('dir cypress\\downloads').then(result => {
  expect(result.stdout).to.include('Concurrent');
  cy.exec('del cypress\\downloads\\*concurrent*.xlsx');
});

